for (const item of $input.all()) {
  // Pega data atual no timezone de São Paulo
  const now = new Date(
    new Date().toLocaleString('en-US', { timeZone: 'America/Sao_Paulo' })
  );

  // Formata para YYYY-MM-DD
  const yyyy = now.getFullYear();
  const mm = String(now.getMonth() + 1).padStart(2, '0');
  const dd = String(now.getDate()).padStart(2, '0');

  item.json.date = `${yyyy}-${mm}-${dd}`;

  return item;
}

return $input.all();

// Lê o primeiro item
const item = $input.first();
const j = item.json || {};

// Acha o data URI (ajuste aqui se vier em outro campo)
const dataUri =
  j?.data?.Data ||
  j?.data?.data ||
  j?.Data ||
  j?.dataUri;

if (!dataUri || typeof dataUri !== 'string') {
  throw new Error('Data URI do áudio não encontrado');
}

// Extrai MIME e a parte base64 (aceita "codecs=..." opcional)
let mime = 'audio/mpeg';
let base64 = '';
const reWithCodecs = /^data:([^;]+);[^,]*;base64,/i;
const reSimple = /^data:([^;]+);base64,/i;

if (reWithCodecs.test(dataUri)) {
  mime = dataUri.match(reWithCodecs)[1];
  base64 = dataUri.replace(reWithCodecs, '');
} else if (reSimple.test(dataUri)) {
  mime = dataUri.match(reSimple)[1];
  base64 = dataUri.replace(reSimple, '');
} else {
  throw new Error('Formato do data URI inválido (sem base64)');
}

if (!base64) throw new Error('Conteúdo base64 do áudio não encontrado');

// Mapeia extensão a partir do MIME
const extMap = {
  'audio/mpeg': 'mp3',
  'audio/mp3': 'mp3',
  'audio/ogg': 'ogg',
  'audio/webm': 'webm',
  'audio/wav': 'wav',
  'audio/x-wav': 'wav',
};
const ext = extMap[mime] || 'mp3';

// Cria buffer
const buffer = Buffer.from(base64, 'base64');

// Prepara o binário do n8n (isso define data/mimeType/fileName corretamente)
const fileName = `audio.${ext}`;
const binary = await this.helpers.prepareBinaryData(buffer, fileName, mime);

// Retorna na propriedade "audio"
return [{
  json: { success: true, mimetype: mime, fileName },
  binary: { audio: binary },
}];

// Extrai os dados do input
const inputData = $input.first().json;

if (!inputData.data || !inputData.data.Data) {
  throw new Error('Dados da imagem não encontrados');
}

// Mantém o data URI completo (OpenAI aceita isso)
const imageDataUrl = inputData.data.Data;

// Cria o payload para a API do OpenAI
return [{
  json: {
    model: "gpt-4o-mini",
    messages: [
      {
        role: "user",
        content: [
          {
            type: "text",
            text: "Descreva essa imagem, oque tem nela?"
          },
          {
            type: "image_url",
            image_url: {
              url: imageDataUrl  // Usa o data URI diretamente
            }
          }
        ]
      }
    ],
    max_tokens: 300
  }
}];

// ============================================================
// FIREWALL DE SPAM - Segunda camada de proteção
// Versão: 2.3 - Documentos permitidos + guardrail de tamanho
// ============================================================

const root = Array.isArray($json) ? $json[0] : $json;

const telefone = root.telefone || "";
const messages = root.messages || "";

const evt = root?.body?.data || root?.data || root || {};
const msg = evt.message || {};
const remoteJid = evt.key?.remoteJid || "";

const phone = telefone || remoteJid.replace(/@.*/, "");

// ============================================================
// GUARDRAIL: limites de tamanho
// ============================================================
const MAX_TEXT_CHARS = 3000;    // ~750 tokens
const MAX_CAPTION_CHARS = 1000; // legenda de imagem/vídeo/doc

// === PALAVRAS/FRASES INDICATIVAS DE SPAM ===
const spamKeywords = [
  "clique aqui",
  "acesse agora",
  "cadastre-se",
  "ganhe dinheiro",
  "renda extra",
  "trabalhe de casa",
  "infinitepay",
  "kwai",
  "shopee",
  "parabens voce foi selecionado",
  "voce ganhou",
  "oferta limitada",
  "ultimas vagas",
  "nao perca essa oportunidade",
];

// === DOMÍNIOS SUSPEITOS ===
const suspiciousDomains = [
  "infinitepay.onelink.me",
  "tinyurl.com",
  "short.link",
  "encurtador.com.br",
  "kwai.com",
  "shopee.com",
];

function normalizeText(text) {
  return (text || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim();
}

// Extrai texto da mensagem
const text = messages ||
             msg.conversation ||
             msg.extendedTextMessage?.text ||
             msg.templateMessage?.hydratedTemplate?.hydratedContentText ||
             msg.buttonsMessage?.contentText ||
             "";

const caption =
  msg.imageMessage?.caption ||
  msg.videoMessage?.caption ||
  msg.documentMessage?.caption || "";

const hasMedia = !!(msg.imageMessage || msg.videoMessage || msg.audioMessage ||
                   msg.documentMessage || msg.documentWithCaptionMessage ||
                   msg.stickerMessage);

const cleanText = text?.trim();
const isEmpty = !cleanText && !hasMedia;

// ============================================================
// REGRA 0 — GUARDRAIL (executa ANTES de tudo)
// ============================================================

// 0a. Texto gigante
if (cleanText && cleanText.length > MAX_TEXT_CHARS) {
  return [{
    ...$json,
    blocked: true,
    firewall: {
      blocked: true,
      reason: "guardrail_text_too_large",
      phone,
      textLength: cleanText.length,
      limit: MAX_TEXT_CHARS,
      textSnippet: cleanText.slice(0, 100) + "..."
    }
  }];
}

// 0b. Caption gigante (legenda de imagem/vídeo/documento)
if (caption && caption.length > MAX_CAPTION_CHARS) {
  return [{
    ...$json,
    blocked: true,
    firewall: {
      blocked: true,
      reason: "guardrail_caption_too_large",
      phone,
      captionLength: caption.length,
      limit: MAX_CAPTION_CHARS
    }
  }];
}

// 0c. Mensagem encaminhada em massa (forward bombing)
const forwardingScore = msg.extendedTextMessage?.contextInfo?.forwardingScore || 0;
if (forwardingScore > 10) {
  return [{
    ...$json,
    blocked: true,
    firewall: {
      blocked: true,
      reason: "guardrail_mass_forward",
      phone,
      forwardingScore
    }
  }];
}

// ============================================================
// REGRA 1 — Mensagem vazia
// ============================================================
if (isEmpty) {
  return [{
    ...$json,
    blocked: true,
    firewall: {
      blocked: true,
      reason: "empty_message",
      phone,
      textLength: text?.length || 0
    }
  }];
}

// ============================================================
// REGRA 2 — Spam por palavras-chave
// ============================================================
const normalizedText = normalizeText(cleanText);
const foundSpamKeyword = spamKeywords.find(keyword =>
  normalizedText.includes(keyword)
);

if (foundSpamKeyword) {
  return [{
    ...$json,
    blocked: true,
    firewall: {
      blocked: true,
      reason: "spam_keyword",
      phone,
      detectedKeyword: foundSpamKeyword,
      textSnippet: cleanText.slice(0, 100)
    }
  }];
}

// ============================================================
// REGRA 3 — Links suspeitos
// ============================================================
const urlRegex = /(https?:\/\/[^\s]+)/gi;
const urls = cleanText?.match(urlRegex) || [];

for (const url of urls) {
  const suspiciousDomain = suspiciousDomains.find(domain =>
    url.toLowerCase().includes(domain)
  );
  if (suspiciousDomain) {
    return [{
      ...$json,
      blocked: true,
      firewall: {
        blocked: true,
        reason: "suspicious_link",
        phone,
        detectedDomain: suspiciousDomain,
        url: url.slice(0, 100)
      }
    }];
  }
}

// ============================================================
// REGRA 4 — Padrão de spam (emojis + links + exclamações)
// ============================================================
const emojiCount = (cleanText?.match(/[\u{1F300}-\u{1F9FF}]/gu) || []).length;
const hasLinks = urls.length > 0;
const exclamationCount = (cleanText?.match(/!/g) || []).length;

if (emojiCount > 3 && hasLinks && exclamationCount > 2) {
  return [{
    ...$json,
    blocked: true,
    firewall: {
      blocked: true,
      reason: "spam_pattern",
      phone,
      pattern: `${emojiCount} emojis + ${urls.length} links + ${exclamationCount} exclamações`,
      textSnippet: cleanText.slice(0, 100)
    }
  }];
}

// ============================================================
// REGRA 5 — Repetição excessiva (copy-paste spam)
// ============================================================
const lines = cleanText?.split('\n') || [];
const uniqueLines = new Set(lines.filter(l => l.trim()));
const repetitionRatio = lines.length > 5 ? uniqueLines.size / lines.length : 1;

if (lines.length > 5 && repetitionRatio < 0.3) {
  return [{
    ...$json,
    blocked: true,
    firewall: {
      blocked: true,
      reason: "repetitive_spam",
      phone,
      totalLines: lines.length,
      uniqueLines: uniqueLines.size,
      repetitionRatio: repetitionRatio.toFixed(2)
    }
  }];
}

// ============================================================
// PERMITIDO — Passou em todos os filtros
// ============================================================
return [{
  ...$json,
  blocked: false,
  firewall: {
    blocked: false,
    reason: "allowed",
    phone,
    textSnippet: cleanText?.slice(0, 50) || "[sem texto]",
    textLength: cleanText?.length || 0
  }
}];

const response = $input.first().json;

// Verifica se o download retornou erro (timeout, falha de conexão, etc.)
if (response.error || !response.data || !response.data.Data) {
  const errorMsg = response.error?.message || 'Resposta inesperada do download de documento';
  return {
    json: {
      fileName: 'erro',
      mimeType: 'text/plain',
      error: true,
      errorMessage: errorMsg
    }
  };
}

const dataUrl = response.data.Data;

// Remove o prefixo "data:application/pdf;base64,"
const base64 = dataUrl.split(',')[1];
const mimeType = dataUrl.split(';')[0].split(':')[1];
const fileName = 'documento.pdf';

const binaryData = Buffer.from(base64, 'base64');

return {
  json: { fileName, mimeType },
  binary: {
    data: await this.helpers.prepareBinaryData(binaryData, fileName, mimeType)
  }
};

// ============================================================
// FILTRO DE MENSAGENS + DETERMINACAO DO CHAT ID
// Versao: 4.2 - Documentos permitidos + guardrail de tamanho
// ============================================================

const items = $input.all();

// === LISTA DE NUMEROS BLOQUEADOS (FRANQUEADOS) ===
const blockedNumbers = [
  "5511930154449","5511968556516","5511993868395","5511978302562",
  "5511976619767","5511994011344","5511944451250","5511919246340",
  "5511978981421","5511949740469","5513991242179","5515996188805",
  "5516996034430","5518996323889","551931997433","5517994022642",
  "5517992172090","5514998798604","5514999093303","5514998543074",
  "5519999980504","5519971241124","5515981124999","5519997335790",
  "5519999278800","5514998841955","5519999453375","5516991930409",
  "5517996086091","5515991386475","5516997185628","5513997670979",
  "5516993252831","5513991103244","5534997981723","5511910811955",
  "5511916596100","5511998351398","5519974022642","5511986849589",
  "5511942030208","5518997208593","5519989798634","5519989141037",
  "5517996642912","5519995457733","553284035355","5515988272579",
  "5511954665864"
];

// === GUARDRAIL: LIMITES DE TAMANHO ===
const MAX_TEXT_CHARS = 3000;    // ~750 tokens
const MAX_CAPTION_CHARS = 1000; // legenda de imagem/vídeo/doc

// === FRASES TIPICAS DE BOTS ===
const botPhrases = [
  "desculpe, nos ainda nao entendemos",
  "desculpe, ainda nao entendemos",
  "nao fique sem resposta",
  "para que voce nao fique sem resposta",
  "digite em poucas palavras",
  "nao conseguimos identificar",
  "nao conseguimos responder por aqui",
  "selecione uma opcao",
  "escolha uma das opcoes",
  "digite o numero da opcao",
  "digite uma das opcoes",
  "responda com o numero",
  "atendimento automatico",
  "sou um assistente virtual",
  "sou a assistente virtual",
  "sou o assistente virtual",
  "mensagem automatica",
  "esse canal nao recebe mensagens",
  "este numero nao recebe mensagens",
  "numero exclusivo para envio",
  "nao entendi, poderia reformular",
  "nao entendi sua mensagem",
  "nao compreendi",
  "tente novamente com outras palavras",
  "por favor, reformule",
];

const botPushNames = ["chatbot", "autoatendimento", "noreply", "no-reply", "notificacao"];

function normalizeText(text) {
  return (text || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim();
}

function extractPhone(jid) {
  if (!jid || jid.endsWith('@lid') || jid.endsWith('@g.us')) return null;
  const phone = jid.split('@')[0].split(':')[0].replace(/\D/g, '');
  return phone.length >= 10 ? phone : null;
}

// ============================================================
// GUARDRAIL: Bloqueia apenas textos/captions gigantes
// Documentos são PERMITIDOS (só caption é checada)
// ============================================================
function isOversizedMessage(message) {
  if (!message) return false;

  const textContent =
    message.conversation ||
    message.extendedTextMessage?.text || '';

  if (textContent.length > MAX_TEXT_CHARS) {
    console.log(`Bloqueado (guardrail): texto com ${textContent.length} chars (limite: ${MAX_TEXT_CHARS})`);
    return true;
  }

  const caption =
    message.imageMessage?.caption ||
    message.videoMessage?.caption ||
    message.documentMessage?.caption || '';

  if (caption.length > MAX_CAPTION_CHARS) {
    console.log(`Bloqueado (guardrail): caption com ${caption.length} chars (limite: ${MAX_CAPTION_CHARS})`);
    return true;
  }

  return false;
}

function isBotMessage(eventData, info, message) {
  if (eventData.IsBotInvoke === true) {
    console.log('Bloqueado: IsBotInvoke=true');
    return true;
  }

  const vName = normalizeText(info.VerifiedName?.Details?.verifiedName || '');
  if (vName && info.IsFromMe !== true) {
    const dangerousNames = ['bot', 'atendimento automatico', 'sistema', 'suporte automatico'];
    if (dangerousNames.some(n => vName.includes(n))) {
      console.log('Bloqueado: VerifiedName "' + vName + '" identificado como sistema.');
      return true;
    }
  }

  const pushName = normalizeText(info.PushName || '');
  if (pushName && info.IsFromMe !== true) {
    const isBotName = botPushNames.some(bn => pushName === bn || pushName.includes('chatbot'));
    if (isBotName) {
      console.log('Bloqueado: PushName="' + info.PushName + '" parece bot');
      return true;
    }
  }

  const rawText = message?.conversation || message?.extendedTextMessage?.text || '';
  const normalizedMsg = normalizeText(rawText);
  if (normalizedMsg) {
    const matchedPhrase = botPhrases.find(phrase =>
      normalizedMsg.length > 15 && normalizedMsg.includes(phrase)
    );
    if (matchedPhrase) {
      console.log('Bloqueado: frase de bot detectada - "' + matchedPhrase + '"');
      return true;
    }
  }

  if (info.IsFromMe !== true) {
    const isBotMsgType = !!(
      message?.listMessage ||
      message?.buttonsMessage ||
      message?.interactiveMessage
    );
    if (isBotMsgType) {
      console.log('Bloqueado: mensagem estruturada de terceiro');
      return true;
    }
  }

  return false;
}

function getEventData(item) {
  if (item.json.body?.data?.event) return item.json.body.data.event;
  if (item.json.data?.event) return item.json.data.event;
  if (item.json.event) return item.json.event;
  if (item.json.Message || item.json.Info) return item.json;
  return null;
}

function determineChatId(info) {
  const isFromMe = info.IsFromMe === true;

  if (!isFromMe) {
    const fromAlt = extractPhone(info.SenderAlt);
    if (fromAlt) return fromAlt;
  } else {
    const toAlt = extractPhone(info.RecipientAlt);
    if (toAlt) return toAlt;
  }

  const target = isFromMe ? (info.Chat || '') : (info.Sender || '');
  const fromTarget = extractPhone(target);
  if (fromTarget) return fromTarget;

  const fallback = isFromMe ? (info.Sender || '') : (info.Chat || '');
  const fromFallback = extractPhone(fallback);
  if (fromFallback) return fromFallback;

  return null;
}

function extractPhoneForCheck(info) {
  const sources = [info.SenderAlt, info.RecipientAlt, info.Chat, info.Sender];
  for (const source of sources) {
    const phone = extractPhone(source);
    if (phone) return phone;
  }
  return null;
}

// === FILTRAR E PROCESSAR MENSAGENS ===
const processedItems = items.filter((item, index) => {
  try {
    const eventData = getEventData(item);
    if (!eventData) return false;

    const message = eventData.Message;
    const info = eventData.Info || {};

    // ⚡ GUARDRAIL PRIMEIRO
    if (isOversizedMessage(message)) return false;

    const phoneToCheck = extractPhoneForCheck(info);
    if (phoneToCheck && blockedNumbers.includes(phoneToCheck)) {
      console.log('Bloqueado (Franqueado): ' + phoneToCheck);
      return false;
    }

    if (message?.protocolMessage) return false;
    if (isBotMessage(eventData, info, message)) return false;

    const hasValidContent = !!(
      message?.conversation ||
      message?.extendedTextMessage?.text ||
      message?.audioMessage ||
      message?.imageMessage ||
      message?.videoMessage ||
      message?.documentMessage ||           // ✅ permitido
      message?.documentWithCaptionMessage || // ✅ permitido
      message?.stickerMessage ||
      message?.locationMessage ||
      message?.contactMessage ||
      message?.contactsArrayMessage
    );

    return hasValidContent;

  } catch (error) {
    console.log('Erro: ' + error.message);
    return true;
  }
}).map(item => {
  const eventData = getEventData(item);
  const info = eventData?.Info || {};
  const chatId = determineChatId(info);
  const needsLookup = chatId === null;

  let lidToLookup = null;
  if (needsLookup) {
    if (info.Chat?.endsWith('@lid')) lidToLookup = info.Chat;
    else if (info.Sender?.endsWith('@lid')) lidToLookup = info.Sender;
    else if (info.SenderAlt?.endsWith('@lid')) lidToLookup = info.SenderAlt;
  }

  const isFromMe = info.IsFromMe === true;
  return {
    ...item,
    json: {
      ...item.json,
      _processado: {
        needsLidLookup: needsLookup,
        chatId: chatId,
        chatIdFinal: chatId,
        lidToLookup: lidToLookup,
        isFromMe: isFromMe,
        event: isFromMe ? 'outcoming' : 'incoming'
      }
    }
  };
});

if (processedItems.length === 0) return [];
return processedItems;

// ============================================================
// PROCESSA RESULTADO DA API DE LID
// ============================================================

const items = $input.all();

return items.map(item => {
  const apiPhone = item.json.data?.phone || null;
  const processado = item.json._processado || {};

  let chatIdFinal = processado.chatId;

  if (apiPhone) {
    chatIdFinal = apiPhone.split('@')[0].split(':')[0].replace(/\D/g, '');
    console.log('✅ Número da API:', chatIdFinal);
  }

  return {
    json: {
      ...item.json,
      _processado: {
        ...processado,
        chatIdFinal: chatIdFinal
      }
    }
  };
});

